export const gameAssetAtlasPixiData = Object.freeze({
  frames: Object.freeze(
    Object.fromEntries(
      Object.entries(gameAssetAtlasFrames).map(([name, frame]) => [
        name,
        Object.freeze({
          frame: Object.freeze({
            x: frame.x,
            y: frame.y,
            w: frame.width,
            h: frame.height,
          }),
          rotated: false,
          trimmed: false,
          spriteSourceSize: Object.freeze({
            x: 0,
            y: 0,
            w: frame.width,
            h: frame.height,
          }),
          sourceSize: Object.freeze({
            w: frame.width,
            h: frame.height,
          }),
        }),
      ]),
    ),
  ),
  meta: Object.freeze({
    image: atlasImageUrl,
    format: 'RGBA8888',
    scale: '1',
    size: Object.freeze({
      w: gameAssetAtlasSize.width,
      h: gameAssetAtlasSize.height,
    }),
  }),
});
